     5→//! Gallops write operations
     6→//!
     7→//! All mutation operations on Gallops: nominate, slate, rail, tally, draft, retire, furlough.
     8→
     9→use std::collections::BTreeMap;
    10→use std::fs;
    11→use std::path::Path;
    12→use crate::jjrf_favor::{jjrf_Firemark as Firemark, jjrf_Coronet as Coronet, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX, JJRF_CORONET_PREFIX as CORONET_PREFIX};
    13→use crate::jjrpd_parade::{jjrpd_format_file_bitmap, jjrpd_format_commit_swimlanes};
    14→use crate::jjrs_steeplechase::jjrs_SteeplechaseEntry as SteeplechaseEntry;
    15→use crate::jjrt_types::*;
    16→use crate::jjru_util::{zjjrg_increment_seed, jjrg_make_tack};
    17→use crate::jjrv_validate::{zjjrg_is_kebab_case, zjjrg_is_yymmdd};
    18→
    19→/// Nominate a new Heat
    20→///
    21→/// Creates a new Heat with empty Pace structure and creates the paddock file.
    22→pub fn jjrg_nominate(gallops: &mut jjrg_Gallops, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
    23→    // Validate silks is alphanumeric-kebab
    24→    if !zjjrg_is_kebab_case(&args.silks) {
    25→        return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", args.silks));
    26→    }
    27→
    28→    // Validate created is YYMMDD
    29→    if !zjjrg_is_yymmdd(&args.created) {
    30→        return Err(format!("created must be YYMMDD format, got '{}'", args.created));
    31→    }
    32→
    33→    // Allocate Firemark from next_heat_seed
    34→    let firemark_str = format!("{}{}", FIREMARK_PREFIX, gallops.next_heat_seed);
    35→    let heat_id = gallops.next_heat_seed.clone();
    36→
    37→    // Compute paddock path
    38→    let paddock_file = format!(".claude/jjm/jjp_{}.md", heat_id);
    39→
    40→    // Create paddock file with template
    41→    let paddock_path = base_path.join(&paddock_file);
    42→    if let Some(parent) = paddock_path.parent() {
    43→        fs::create_dir_all(parent)
    44→            .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
    45→    }
    46→
    47→    let paddock_content = format!(
    48→        "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
    49→        args.silks
    50→    );
    51→
    52→    fs::write(&paddock_path, paddock_content)
    53→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
    54→
    55→    // Create new Heat
    56→    let heat = jjrg_Heat {
    57→        silks: args.silks,
    58→        creation_time: args.created,
    59→        status: jjrg_HeatStatus::Stabled,
    60→        order: Vec::new(),
    61→        next_pace_seed: "AAA".to_string(),
    62→        paddock_file,
    63→        paces: BTreeMap::new(),
    64→    };
    65→
    66→    // Insert Heat
    67→    gallops.heats.insert(firemark_str.clone(), heat);
    68→
    69→    // Increment next_heat_seed
    70→    gallops.next_heat_seed = zjjrg_increment_seed(&gallops.next_heat_seed);
    71→
    72→    Ok(jjrg_NominateResult { firemark: firemark_str })
    73→}
    74→
    75→/// Slate a new Pace
    76→///
    77→/// Adds a new Pace to a Heat with an initial Tack in rough state.
    78→/// Positioning: use before/after/first to insert at specific location.
    79→pub fn jjrg_slate(gallops: &mut jjrg_Gallops, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
    80→    // Validate silks is alphanumeric-kebab
    81→    if !zjjrg_is_kebab_case(&args.silks) {
    82→        return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", args.silks));
    83→    }
    84→
    85→    // Validate text is non-empty
    86→    if args.text.is_empty() {
    87→        return Err("text must not be empty".to_string());
    88→    }
    89→
    90→    // Validate positioning mutual exclusivity
    91→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
    92→        .iter()
    93→        .filter(|&&x| x)
    94→        .count();
    95→    if position_count > 1 {
    96→        return Err("Only one of --before, --after, or --first may be specified".to_string());
    97→    }
    98→
    99→    // Parse and normalize firemark
   100→    let firemark = Firemark::jjrf_parse(&args.firemark)
   101→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   102→    let firemark_key = firemark.jjrf_display();
   103→
   104→    // Verify Heat exists
   105→    let heat = gallops.heats.get_mut(&firemark_key)
   106→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   107→
   108→    // If --before or --after specified, validate target coronet exists
   109→    let insert_position = if let Some(ref before_str) = args.before {
   110→        let target = Coronet::jjrf_parse(before_str)
   111→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   112→        let target_key = target.jjrf_display();
   113→        let pos = heat.order.iter().position(|c| c == &target_key)
   114→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   115→        Some(pos) // Insert before this position
   116→    } else if let Some(ref after_str) = args.after {
   117→        let target = Coronet::jjrf_parse(after_str)
   118→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   119→        let target_key = target.jjrf_display();
   120→        let pos = heat.order.iter().position(|c| c == &target_key)
   121→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   122→        Some(pos + 1) // Insert after this position
   123→    } else if args.first {
   124→        Some(0) // Insert at beginning
   125→    } else {
   126→        None // Append to end (default)
   127→    };
   128→
   129→    // Construct Coronet
   130→    let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   131→
   132→    // Create initial Tack and Pace
   133→    let tack = jjrg_make_tack(
   134→        jjrg_PaceState::Rough,
   135→        args.text,
   136→        args.silks,
   137→        None,
   138→    );
   139→    let pace = jjrg_Pace {
   140→        tacks: vec![tack],
   141→    };
   142→
   143→    // Insert into order at determined position
   144→    match insert_position {
   145→        Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   146→        None => heat.order.push(coronet_str.clone()),
   147→    }
   148→    heat.paces.insert(coronet_str.clone(), pace);
   149→
   150→    // Increment next_pace_seed
   151→    heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   152→
   153→    Ok(jjrg_SlateResult { coronet: coronet_str })
   154→}
   155→
   156→/// Rail - reorder Paces within a Heat
   157→///
   158→/// Supports two modes:
   159→/// - Order mode: replace entire sequence with provided order array
   160→/// - Move mode: relocate a single pace using positioning flags
   161→pub fn jjrg_rail(gallops: &mut jjrg_Gallops, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   162→    // Parse and normalize firemark
   163→    let firemark = Firemark::jjrf_parse(&args.firemark)
   164→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   165→    let firemark_key = firemark.jjrf_display();
   166→
   167→    // Verify Heat exists
   168→    let heat = gallops.heats.get_mut(&firemark_key)
   169→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   170→
   171→    // Mode detection: if move_coronet present, use move mode
   172→    if let Some(ref move_str) = args.move_coronet {
   173→        // Move mode validation
   174→        if !args.order.is_empty() {
   175→            return Err("Cannot combine --move with positional coronets".to_string());
   176→        }
   177→
   178→        // Parse and normalize move coronet
   179→        let move_coronet = Coronet::jjrf_parse(move_str)
   180→            .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   181→        let move_key = move_coronet.jjrf_display();
   182→
   183→        // Validate move coronet exists in heat
   184→        if !heat.paces.contains_key(&move_key) {
   185→            return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   186→        }
   187→
   188→        // Count positioning flags
   189→        let position_count = [
   190→            args.before.is_some(),
   191→            args.after.is_some(),
   192→            args.first,
   193→            args.last,
   194→        ].iter().filter(|&&x| x).count();
   195→
   196→        if position_count == 0 {
   197→            return Err("Move mode requires exactly one positioning flag".to_string());
   198→        }
   199→        if position_count > 1 {
   200→            let mut flags = Vec::new();
   201→            if args.before.is_some() { flags.push("--before"); }
   202→            if args.after.is_some() { flags.push("--after"); }
   203→            if args.first { flags.push("--first"); }
   204→            if args.last { flags.push("--last"); }
   205→            return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   206→        }
   207→
   208→        // Determine target position and validate
   209→        let current_pos = heat.order.iter().position(|c| c == &move_key)
   210→            .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   211→
   212→        let new_pos = if args.first {
   213→            // Find first actionable pace (rough or bridled)
   214→            // If none found, use end of array (nothing actionable to precede)
   215→            let first_actionable_idx = heat.order.iter().position(|coronet| {
   216→                if let Some(pace) = heat.paces.get(coronet) {
   217→                    if let Some(tack) = pace.tacks.first() {
   218→                        matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   219→                    } else {
   220→                        false
   221→                    }
   222→                } else {
   223→                    false
   224→                }
   225→            });
   226→            // Use len() as fallback so adjustment logic works correctly for "end" position
   227→            let target_idx = first_actionable_idx.unwrap_or(heat.order.len());
   228→            // If moving from before target, the target shifts down after removal
   229→            if current_pos < target_idx {
   230→                target_idx - 1
   231→            } else {
   232→                target_idx
   233→            }
   234→        } else if args.last {
   235→            heat.order.len() - 1
   236→        } else if let Some(ref before_str) = args.before {
   237→            let target = Coronet::jjrf_parse(before_str)
   238→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   239→            let target_key = target.jjrf_display();
   240→
   241→            if target_key == move_key {
   242→                return Err("Cannot position pace relative to itself".to_string());
   243→            }
   244→
   245→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   246→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   247→
   248→            // If moving from before target, the target shifts down after removal
   249→            if current_pos < target_pos {
   250→                target_pos - 1
   251→            } else {
   252→                target_pos
   253→            }
   254→        } else if let Some(ref after_str) = args.after {
   255→            let target = Coronet::jjrf_parse(after_str)
   256→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   257→            let target_key = target.jjrf_display();
   258→
   259→            if target_key == move_key {
   260→                return Err("Cannot position pace relative to itself".to_string());
   261→            }
   262→
   263→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   264→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   265→
   266→            // If moving from before target, the target shifts down after removal
   267→            if current_pos < target_pos {
   268→                target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   269→            } else {
   270→                target_pos + 1
   271→            }
   272→        } else {
   273→            unreachable!()
   274→        };
   275→
   276→        // Remove from current position and insert at new position
   277→        heat.order.remove(current_pos);
   278→        heat.order.insert(new_pos, move_key);
   279→
   280→    } else {
   281→        // Order mode has been removed
   282→        if !args.order.is_empty() {
   283→            return Err("Order mode removed. Use --move to reposition individual paces.".to_string());
   284→        }
   285→        return Err("No --move specified. Use --move CORONET with a positioning flag (--first, --last, --before, --after).".to_string());
   286→    }
   287→
   288→    // Return the new order
   289→    Ok(heat.order.clone())
   290→}
   291→
   292→/// Tally - add a new Tack to a Pace
   293→///
   294→/// Prepends a new Tack with state transition and/or plan refinement.
   295→pub fn jjrg_tally(gallops: &mut jjrg_Gallops, args: jjrg_TallyArgs) -> Result<(), String> {
   296→    // Parse and normalize coronet
   297→    let coronet = Coronet::jjrf_parse(&args.coronet)
   298→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   299→    let coronet_key = coronet.jjrf_display();
   300→
   301→    // Extract parent Firemark
   302→    let firemark = coronet.jjrf_parent_firemark();
   303→    let firemark_key = firemark.jjrf_display();
   304→
   305→    // Verify Heat exists
   306→    let heat = gallops.heats.get_mut(&firemark_key)
   307→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   308→
   309→    // Verify Pace exists
   310→    let pace = heat.paces.get_mut(&coronet_key)
   311→        .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
   312→
   313→    // Read current Tack
   314→    let current_tack = pace.tacks.first()
   315→        .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
   316→
   317→    // Check for the new-spec-invalidates-bridled condition:
   318→    // If pace is currently bridled AND new spec text is provided AND no explicit --state,
   319→    // then auto-reset to rough (new spec invalidates old direction)
   320→    let auto_reset_to_rough = args.state.is_none()
   321→        && matches!(current_tack.state, jjrg_PaceState::Bridled)
   322→        && args.text.is_some();
   323→
   324→    // Determine new state
   325→    let new_state = if auto_reset_to_rough {
   326→        jjrg_PaceState::Rough
   327→    } else {
   328→        args.state.clone().unwrap_or_else(|| current_tack.state.clone())
   329→    };
   330→
   331→    // Determine new direction
   332→    let new_direction = match (&args.state, &new_state) {
   333→        // State explicitly set to bridled: direction required
   334→        (Some(jjrg_PaceState::Bridled), _) => {
   335→            match &args.direction {
   336→                Some(d) if !d.is_empty() => Some(d.clone()),
   337→                Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
   338→                None => return Err("direction is required when state is bridled".to_string()),
   339→            }
   340→        }
   341→        // State explicitly set to something other than bridled: direction forbidden
   342→        (Some(_), _) => {
   343→            if args.direction.is_some() {
   344→                return Err("direction must be absent when state is not bridled".to_string());
   345→            }
   346→            None
   347→        }
   348→        // Auto-reset to rough: no direction
   349→        _ if auto_reset_to_rough => None,
   350→        // State inherited and was bridled: inherit direction
   351→        (None, jjrg_PaceState::Bridled) => {
   352→            args.direction.or_else(|| current_tack.direction.clone())
   353→        }
   354→        // State inherited and was not bridled: no direction
   355→        (None, _) => None,
   356→    };
   357→
   358→    // Determine new text
   359→    let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
   360→    if new_text.is_empty() {
   361→        return Err("text must not be empty".to_string());
   362→    }
   363→
   364→    // Determine new silks
   365→    let new_silks = args.silks.unwrap_or_else(|| current_tack.silks.clone());
   366→
   367→    // Create new Tack
   368→    let new_tack = jjrg_make_tack(
   369→        new_state,
   370→        new_text,
   371→        new_silks,
   372→        new_direction,
   373→    );
   374→
   375→    // Prepend to tacks array
   376→    pace.tacks.insert(0, new_tack);
   377→
   378→    Ok(())
   379→}
   380→
   381→/// Draft - move a Pace from one Heat to another
   382→///
   383→/// Moves the pace to the destination heat with a new Coronet.
   384→/// All Tack history is preserved, with a new Tack recording the draft.
   385→/// State is NOT changed - draft is a move operation, not a state transition.
   386→pub fn jjrg_draft(gallops: &mut jjrg_Gallops, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
   387→    // Validate positioning mutual exclusivity
   388→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   389→        .iter()
   390→        .filter(|&&x| x)
   391→        .count();
   392→    if position_count > 1 {
   393→        return Err("Only one of --before, --after, or --first may be specified".to_string());
   394→    }
   395→
   396→    // Parse and normalize source coronet
   397→    let source_coronet = Coronet::jjrf_parse(&args.coronet)
   398→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   399→    let source_coronet_key = source_coronet.jjrf_display();
   400→
   401→    // Extract source Firemark from coronet
   402→    let source_firemark = source_coronet.jjrf_parent_firemark();
   403→    let source_firemark_key = source_firemark.jjrf_display();
   404→
   405→    // Parse and normalize destination firemark
   406→    let dest_firemark = Firemark::jjrf_parse(&args.to)
   407→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
   408→    let dest_firemark_key = dest_firemark.jjrf_display();
   409→
   410→    // Validate source and destination are different
   411→    if source_firemark_key == dest_firemark_key {
   412→        return Err("Cannot draft pace to same heat".to_string());
   413→    }
   414→
   415→    // Verify source heat exists
   416→    if !gallops.heats.contains_key(&source_firemark_key) {
   417→        return Err(format!("Source heat '{}' not found", source_firemark_key));
   418→    }
   419→
   420→    // Verify destination heat exists
   421→    if !gallops.heats.contains_key(&dest_firemark_key) {
   422→        return Err(format!("Heat '{}' not found", dest_firemark_key));
   423→    }
   424→
   425→    // Verify pace exists in source heat
   426→    {
   427→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
   428→        if !source_heat.paces.contains_key(&source_coronet_key) {
   429→            return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
   430→        }
   431→    }
   432→
   433→    // Validate positioning target if specified
   434→    let insert_position = if let Some(ref before_str) = args.before {
   435→        let target = Coronet::jjrf_parse(before_str)
   436→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   437→        let target_key = target.jjrf_display();
   438→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   439→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   440→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   441→        Some(pos)
   442→    } else if let Some(ref after_str) = args.after {
   443→        let target = Coronet::jjrf_parse(after_str)
   444→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   445→        let target_key = target.jjrf_display();
   446→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   447→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   448→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   449→        Some(pos + 1)
   450→    } else if args.first {
   451→        Some(0)
   452→    } else {
   453→        None // Append to end
   454→    };
   455→
   456→    // Remove pace from source heat
   457→    let source_heat = gallops.heats.get_mut(&source_firemark_key).unwrap();
   458→    let pace_data = source_heat.paces.remove(&source_coronet_key)
   459→        .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
   460→    source_heat.order.retain(|c| c != &source_coronet_key);
   461→
   462→    // Get destination heat and allocate new coronet
   463→    let dest_heat = gallops.heats.get_mut(&dest_firemark_key).unwrap();
   464→    let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
   465→
   466→    // Create new tack recording the draft
   467→    let first_tack = pace_data.tacks.first();
   468→    let draft_note = format!("Drafted from {} in {}.\n\n{}",
   469→        source_coronet_key, source_firemark_key,
   470→        first_tack.map(|t| t.text.as_str()).unwrap_or(""));
   471→
   472→    let draft_tack = jjrg_make_tack(
   473→        first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
   474→        draft_note,
   475→        first_tack.map(|t| t.silks.clone()).unwrap_or_default(),
   476→        first_tack.and_then(|t| t.direction.clone()),
   477→    );
   478→
   479→    // Build new pace with draft tack prepended
   480→    let mut new_tacks = vec![draft_tack];
   481→    new_tacks.extend(pace_data.tacks);
   482→
   483→    let new_pace = jjrg_Pace {
   484→        tacks: new_tacks,
   485→    };
   486→
   487→    // Insert into destination heat
   488→    match insert_position {
   489→        Some(pos) => dest_heat.order.insert(pos, new_coronet_str.clone()),
   490→        None => dest_heat.order.push(new_coronet_str.clone()),
   491→    }
   492→    dest_heat.paces.insert(new_coronet_str.clone(), new_pace);
   493→
   494→    // Increment destination seed
   495→    dest_heat.next_pace_seed = zjjrg_increment_seed(&dest_heat.next_pace_seed);
   496→
   497→    Ok(jjrg_DraftResult { new_coronet: new_coronet_str })
   498→}
