   500→/// Retire a Heat
   501→///
   502→/// Creates trophy file, removes heat from gallops, deletes paddock file.
   503→/// Does NOT save gallops or commit - caller is responsible for that.
   504→pub fn jjrg_retire(
   505→    gallops: &mut jjrg_Gallops,
   506→    args: jjrg_RetireArgs,
   507→    base_path: &Path,
   508→    steeplechase: &[SteeplechaseEntry],
   509→) -> Result<jjrg_RetireResult, String> {
   510→    // Parse and normalize firemark
   511→    let firemark = Firemark::jjrf_parse(&args.firemark)
   512→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   513→    let firemark_key = firemark.jjrf_display();
   514→
   515→    // Validate today is YYMMDD
   516→    if !zjjrg_is_yymmdd(&args.today) {
   517→        return Err(format!("today must be YYMMDD format, got '{}'", args.today));
   518→    }
   519→
   520→    // Verify heat exists
   521→    let heat = gallops.heats.get(&firemark_key)
   522→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   523→
   524→    // Read paddock content before we remove anything
   525→    let paddock_path = base_path.join(&heat.paddock_file);
   526→    let paddock_content = fs::read_to_string(&paddock_path)
   527→        .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
   528→
   529→    // Build trophy content
   530→    let trophy_content = zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
   531→
   532→    // Compute trophy path: .claude/jjm/retired/jjh_b<created>-r<today>-<silks>.md
   533→    let trophy_filename = format!(
   534→        "jjh_b{}-r{}-{}.md",
   535→        heat.creation_time,
   536→        args.today,
   537→        heat.silks
   538→    );
   539→    let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
   540→    let trophy_full_path = base_path.join(&trophy_rel_path);
   541→
   542→    // Create retired directory if needed
   543→    if let Some(parent) = trophy_full_path.parent() {
   544→        fs::create_dir_all(parent)
   545→            .map_err(|e| format!("Failed to create retired directory: {}", e))?;
   546→    }
   547→
   548→    // Write trophy file
   549→    fs::write(&trophy_full_path, trophy_content)
   550→        .map_err(|e| format!("Failed to write trophy file: {}", e))?;
   551→
   552→    // Capture info for result before removing heat
   553→    let silks = heat.silks.clone();
   554→    let paddock_file = heat.paddock_file.clone();
   555→
   556→    // Remove heat from gallops (do NOT change next_heat_seed)
   557→    // Use shift_remove to preserve order of remaining heats
   558→    gallops.heats.shift_remove(&firemark_key);
   559→
   560→    // Delete paddock file
   561→    if paddock_path.exists() {
   562→        fs::remove_file(&paddock_path)
   563→            .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
   564→    }
   565→
   566→    Ok(jjrg_RetireResult {
   567→        trophy_path: trophy_rel_path,
   568→        paddock_path: paddock_file,
   569→        silks,
   570→        firemark: firemark_key,
   571→    })
   572→}
