   596→/// Build trophy markdown content
   597→fn zjjrg_build_trophy_content(
   598→    firemark_key: &str,
   599→    heat: &jjrg_Heat,
   600→    paddock_content: &str,
   601→    today: &str,
   602→    steeplechase: &[SteeplechaseEntry],
   603→) -> Result<String, String> {
   604→    let mut content = String::new();
   605→
   606→    // Header
   607→    content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
   608→    content.push_str(&format!("**Firemark:** {}\n", firemark_key));
   609→    content.push_str(&format!("**Created:** {}\n", heat.creation_time));
   610→    content.push_str(&format!("**Retired:** {}\n", today));
   611→    content.push_str("**Status:** retired\n\n");
   612→
   613→    // Paddock
   614→    content.push_str("## Paddock\n\n");
   615→    content.push_str(paddock_content);
   616→    if !paddock_content.ends_with('\n') {
   617→        content.push('\n');
   618→    }
   619→    content.push('\n');
   620→
   621→    // Paces (in order)
   622→    content.push_str("## Paces\n\n");
   623→    for coronet_key in &heat.order {
   624→        if let Some(pace) = heat.paces.get(coronet_key) {
   625→            // Get final state from most recent tack
   626→            let final_state = pace.tacks.first()
   627→                .map(|t| match t.state {
   628→                    jjrg_PaceState::Rough => "rough",
   629→                    jjrg_PaceState::Bridled => "bridled",
   630→                    jjrg_PaceState::Complete => "complete",
   631→                    jjrg_PaceState::Abandoned => "abandoned",
   632→                })
   633→                .unwrap_or("unknown");
   634→
   635→            let pace_silks = pace.tacks.first()
   636→                .map(|t| t.silks.as_str())
   637→                .unwrap_or("unknown");
   638→
   639→            content.push_str(&format!(
   640→                "### {} ({}) [{}]\n\n",
   641→                pace_silks, coronet_key, final_state
   642→            ));
   643→
   644→            // Tack history (newest first, as stored)
   645→            for tack in &pace.tacks {
   646→                let state_str = match tack.state {
   647→                    jjrg_PaceState::Rough => "rough",
   648→                    jjrg_PaceState::Bridled => "bridled",
   649→                    jjrg_PaceState::Complete => "complete",
   650→                    jjrg_PaceState::Abandoned => "abandoned",
   651→                };
   652→                content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
   653→                content.push_str(&tack.text);
   654→                if !tack.text.ends_with('\n') {
   655→                    content.push('\n');
   656→                }
   657→                if let Some(ref direction) = tack.direction {
   658→                    content.push_str(&format!("\n*Direction:* {}\n", direction));
   659→                }
   660→                content.push('\n');
   661→            }
   662→        }
   663→    }
   664→
   665→    // Commit Activity (bitmap views)
   666→    let firemark = Firemark::jjrf_parse(firemark_key)
   667→        .map_err(|e| format!("Invalid firemark in trophy builder: {}", e))?;
   668→    content.push_str("## Commit Activity\n\n");
   669→    content.push_str("```\n");
   670→    if let Ok(bitmap) = jjrpd_format_file_bitmap(&firemark, heat) {
   671→        content.push_str(&bitmap);
   672→    }
   673→    if let Ok(swimlanes) = jjrpd_format_commit_swimlanes(&firemark, heat) {
   674→        content.push_str(&swimlanes);
   675→    }
   676→    content.push_str("```\n\n");
   677→
   678→    // Steeplechase (newest first, as provided)
   679→    content.push_str("## Steeplechase\n\n");
   680→    if steeplechase.is_empty() {
   681→        content.push_str("(no entries)\n\n");
   682→    } else {
   683→        for entry in steeplechase {
   684→            // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
   685→            let identity = entry.coronet.as_deref().unwrap_or("Heat");
   686→            let action = entry.action.as_deref().unwrap_or("notch");
   687→            content.push_str(&format!(
   688→                "### {} - {} - {}\n\n",
   689→                entry.timestamp, identity, action
   690→            ));
   691→            content.push_str(&entry.subject);
   692→            if !entry.subject.ends_with('\n') {
   693→                content.push('\n');
   694→            }
   695→            content.push('\n');
   696→        }
   697→    }
   698→
   699→    Ok(content)
   700→}
