   702→/// Curry - update Heat paddock with chalk entry
   703→///
   704→/// Writes new paddock content and creates a chalk commit recording the change.
   705→pub fn jjrg_curry(
   706→    gallops_path: &std::path::Path,
   707→    firemark: &Firemark,
   708→    new_content: &str,
   709→    note: Option<&str>,
   710→) -> Result<(), String> {
   711→    use std::fs;
   712→
   713→    // Load gallops
   714→    let gallops = jjrg_Gallops::jjrg_load(gallops_path)
   715→        .map_err(|e| format!("Failed to load Gallops: {}", e))?;
   716→
   717→    // Verify heat exists
   718→    let firemark_key = firemark.jjrf_display();
   719→    let heat = gallops.heats.get(&firemark_key)
   720→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   721→
   722→    // Write new paddock content
   723→    let paddock_path = std::path::Path::new(&heat.paddock_file);
   724→    fs::write(paddock_path, new_content)
   725→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   726→
   727→    // Build chalk message
   728→    let description = if let Some(n) = note {
   729→        format!("paddock curried: {}", n)
   730→    } else {
   731→        "paddock curried".to_string()
   732→    };
   733→
   734→    // Create chalk commit using vvc
   735→    use crate::jjrn_notch::jjrn_format_heat_discussion;
   736→    let message = jjrn_format_heat_discussion(firemark, &description);
   737→
   738→    let commit_args = vvc::vvcm_CommitArgs {
   739→        files: vec![paddock_path.to_string_lossy().to_string()],
   740→        message,
   741→        size_limit: vvc::VVCG_SIZE_LIMIT,
   742→        warn_limit: vvc::VVCG_WARN_LIMIT,
   743→    };
   744→
   745→    // Acquire lock for commit
   746→    let lock = vvc::vvcc_CommitLock::vvcc_acquire()
   747→        .map_err(|e| format!("Failed to acquire commit lock: {}", e))?;
   748→
   749→    match vvc::machine_commit(&lock, &commit_args) {
   750→        Ok(hash) => {
   751→            eprintln!("jjx_curry: committed {}", &hash[..8]);
   752→            Ok(())
   753→        }
   754→        Err(e) => Err(format!("Commit failed: {}", e)),
   755→    }
   756→    // lock released here
   757→}
