   759→/// Furlough a Heat - change status or rename
   760→///
   761→/// Updates heat status (racing/stabled) and/or silks.
   762→/// At least one change must be requested.
   763→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
   764→    // Validate at least one option provided
   765→    if !args.racing && !args.stabled && args.silks.is_none() {
   766→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
   767→    }
   768→
   769→    // Validate racing/stabled mutual exclusivity
   770→    if args.racing && args.stabled {
   771→        return Err("Cannot specify both --racing and --stabled".to_string());
   772→    }
   773→
   774→    // Validate silks if provided
   775→    if let Some(ref silks) = args.silks {
   776→        if !zjjrg_is_kebab_case(silks) {
   777→            return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", silks));
   778→        }
   779→    }
   780→
   781→    // Parse and normalize firemark
   782→    let firemark = Firemark::jjrf_parse(&args.firemark)
   783→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   784→    let firemark_key = firemark.jjrf_display();
   785→
   786→    // Verify Heat exists and check status
   787→    {
   788→        let heat = gallops.heats.get(&firemark_key)
   789→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   790→
   791→        // Check not retired (terminal state)
   792→        if heat.status == jjrg_HeatStatus::Retired {
   793→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
   794→        }
   795→
   796→        // Note: requesting the same status is allowed — it promotes the heat
   797→        // to the top of its list (racing or stabled) for reordering purposes.
   798→    }
   799→
   800→    // Apply status change if requested — also promotes heat to top of list
   801→    if args.racing {
   802→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
   803→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
   804→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
   805→        }
   806→    } else if args.stabled {
   807→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
   808→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
   809→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
   810→        }
   811→    }
   812→
   813→    // Apply silks change if requested
   814→    if let Some(silks) = args.silks {
   815→        gallops.heats.get_mut(&firemark_key).unwrap().silks = silks;
   816→    }
   817→
   818→    Ok(())
   819→}
   820→
   821→/// Garland a Heat - celebrate completion and create continuation
   822→///
   823→/// Updates source heat silks to garlanded form and status to stabled.
   824→/// Creates new heat with continuation silks, status racing.
   825→/// Transfers actionable paces (rough/bridled) to new heat.
   826→/// Retains complete/abandoned paces in garlanded heat.
   827→pub fn jjrg_garland(gallops: &mut jjrg_Gallops, args: jjrg_GarlandArgs, base_path: &Path) -> Result<jjrg_GarlandResult, String> {
   828→    use crate::jjrc_core::jjrc_timestamp_from_env;
   829→    use crate::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
   830→
   831→    // Parse and normalize firemark
   832→    let firemark = Firemark::jjrf_parse(&args.firemark)
   833→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   834→    let firemark_key = firemark.jjrf_display();
   835→
   836→    // Verify source heat exists and extract needed data (avoid holding the borrow)
   837→    let (source_silks, source_paddock_file, source_order, actionable_count, retained_count) = {
   838→        let source_heat = gallops.heats.get(&firemark_key)
   839→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   840→
   841→        // Parse source silks to determine sequence
   842→        let (base, sequence) = jjrq_parse_silks_sequence(&source_heat.silks);
   843→        let seq = sequence.unwrap_or(1);
   844→
   845→        // Count actionable paces
   846→        let actionable_count = source_heat.order.iter().filter(|coronet_key| {
   847→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   848→                if let Some(tack) = pace.tacks.first() {
   849→                    matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   850→                } else {
   851→                    false
   852→                }
   853→            } else {
   854→                false
   855→            }
   856→        }).count();
   857→
   858→        // Validate there are actionable paces to transfer
   859→        if actionable_count == 0 {
   860→            return Err(format!("Heat '{}' has no actionable paces to transfer", firemark_key));
   861→        }
   862→
   863→        // Count retained paces
   864→        let retained_count = source_heat.paces.len() - actionable_count;
   865→
   866→        // Count complete paces for steeplechase marker
   867→        let complete_count = source_heat.order.iter().filter(|coronet_key| {
   868→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   869→                if let Some(tack) = pace.tacks.first() {
   870→                    tack.state == jjrg_PaceState::Complete
   871→                } else {
   872→                    false
   873→                }
   874→            } else {
   875→                false
   876→            }
   877→        }).count();
   878→
   879→        // Create steeplechase marker entry
   880→        let marker_text = format!("Garlanded at pace {} — magnificent service", complete_count);
   881→
   882→        // Update source heat: add steeplechase marker (prepend to paddock file)
   883→        let source_paddock_path = base_path.join(&source_heat.paddock_file);
   884→        let existing_content = std::fs::read_to_string(&source_paddock_path)
   885→            .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   886→
   887→        let updated_content = format!("{}\n\n{}", marker_text, existing_content);
   888→        std::fs::write(&source_paddock_path, updated_content)
   889→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   890→
   891→        ((base, seq), source_heat.paddock_file.clone(), source_heat.order.clone(), actionable_count, retained_count)
   892→    };
   893→
   894→    // Build garlanded and continuation silks
   895→    let (base, seq) = source_silks;
   896→    let garlanded_silks = jjrq_build_garlanded_silks(&base, seq);
   897→    let continuation_silks = jjrq_build_continuation_silks(&base, seq + 1);
   898→
   899→    // Nominate new heat with continuation silks
   900→    let created_ts = jjrc_timestamp_from_env();
   901→    let nominate_args = jjrg_NominateArgs {
   902→        silks: continuation_silks.clone(),
   903→        created: created_ts,
   904→    };
   905→    let nominate_result = jjrg_nominate(gallops, nominate_args, base_path)?;
   906→    let new_firemark_key = nominate_result.firemark.clone();
   907→
   908→    // Get destination heat paddock file for copy
   909→    let dest_paddock_file = {
   910→        let dest_heat = gallops.heats.get(&new_firemark_key)
   911→            .ok_or_else(|| "Failed to retrieve newly nominated heat".to_string())?;
   912→        dest_heat.paddock_file.clone()
   913→    };
   914→
   915→    // Read original paddock content before modifications (for new heat)
   916→    let source_paddock_path = base_path.join(&source_paddock_file);
   917→    let original_paddock_content = std::fs::read_to_string(&source_paddock_path)
   918→        .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   919→
   920→    // Extract original content (removing marker we just added)
   921→    let existing_content = original_paddock_content.split_once("\n\n")
   922→        .map(|(_, rest)| rest)
   923→        .unwrap_or(&original_paddock_content);
   924→
   925→    // Copy paddock content from source to new heat
   926→    let dest_paddock_path = base_path.join(&dest_paddock_file);
   927→    std::fs::write(&dest_paddock_path, existing_content)
   928→        .map_err(|e| format!("Failed to copy paddock to new heat: {}", e))?;
   929→
   930→    // Draft all actionable paces to new heat (in order)
   931→    for coronet_key in source_order {
   932→        if let Some(pace) = gallops.heats.get(&firemark_key).unwrap().paces.get(&coronet_key) {
   933→            if let Some(tack) = pace.tacks.first() {
   934→                if matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled) {
   935→                    // Draft this pace to new heat (append to end)
   936→                    let draft_args = jjrg_DraftArgs {
   937→                        coronet: coronet_key.clone(),
   938→                        to: new_firemark_key.clone(),
   939→                        before: None,
   940→                        after: None,
   941→                        first: false, // Append to end to maintain order
   942→                    };
   943→                    jjrg_draft(gallops, draft_args)?;
   944→                }
   945→            }
   946→        }
   947→    }
   948→
   949→    // Update source heat: change silks to garlanded, set status to stabled
   950→    let source_heat_mut = gallops.heats.get_mut(&firemark_key).unwrap();
   951→    source_heat_mut.silks = garlanded_silks.clone();
   952→    source_heat_mut.status = jjrg_HeatStatus::Stabled;
   953→
   954→    // Set new heat status to racing and move to front
   955→    let new_heat_mut = gallops.heats.get_mut(&new_firemark_key).unwrap();
   956→    new_heat_mut.status = jjrg_HeatStatus::Racing;
   957→    if let Some(heat_entry) = gallops.heats.shift_remove(&new_firemark_key) {
   958→        gallops.heats.shift_insert(0, new_firemark_key.clone(), heat_entry);
   959→    }
   960→
   961→    Ok(jjrg_GarlandResult {
   962→        old_firemark: firemark_key,
   963→        old_silks: garlanded_silks,
   964→        new_firemark: new_firemark_key,
   965→        new_silks: continuation_silks,
   966→        paces_transferred: actionable_count,
   967→        paces_retained: retained_count,
   968→    })
   969→}
   970→
   971→/// Restring - bulk draft multiple paces atomically
   972→///
   973→/// Moves multiple paces from source heat to destination heat in a single operation.
   974→/// All paces are validated before any mutations occur.
   975→/// Order is preserved in the destination heat.
   976→pub fn jjrg_restring(gallops: &mut jjrg_Gallops, args: jjrg_RestringArgs) -> Result<jjrg_RestringResult, String> {
   977→    // Parse and normalize firemarks
   978→    let source_firemark = Firemark::jjrf_parse(&args.source_firemark)
   979→        .map_err(|e| format!("Invalid source firemark: {}", e))?;
   980→    let source_firemark_key = source_firemark.jjrf_display();
   981→
   982→    let dest_firemark = Firemark::jjrf_parse(&args.dest_firemark)
   983→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
   984→    let dest_firemark_key = dest_firemark.jjrf_display();
   985→
