   135→/// Save Gallops to a file with validation
   136→///
   137→/// Performs atomic write with validation:
   138→/// 1. Serialize to JSON
   139→/// 2. Write to temp file
   140→/// 3. Validate temp file via jjdr_load
   141→/// 4. Rename temp to target (atomic)
   142→///
   143→/// If validation fails, temp file is deleted and error returned.
   144→pub fn jjdr_save(gallops: &jjrg_Gallops, path: &Path) -> Result<(), String> {
   145→    // Serialize to pretty JSON
   146→    let json = serde_json::to_string_pretty(gallops)
   147→        .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
   148→
   149→    // Create temp file in same directory for atomic rename
   150→    let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
   151→    let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
   152→
   153→    // Write to temp file
   154→    fs::write(&temp_path, &json)
   155→        .map_err(|e| format!("Failed to write temp file: {}", e))?;
   156→
   157→    // Validate what we wrote by loading it back
   158→    match jjdr_load(&temp_path) {
   159→        Ok(_) => {
   160→            // Validation passed, rename to target
   161→            fs::rename(&temp_path, path)
   162→                .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
   163→            Ok(())
   164→        }
   165→        Err(e) => {
   166→            // Validation failed, clean up temp file
   167→            let _ = fs::remove_file(&temp_path);
   168→            Err(format!("Save validation failed: {}", e))
   169→        }
   170→    }
   171→}

